import json
import os
import functions_framework
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
from datetime import datetime


# Environment variables (set in deployment)
PROJECT_ID = os.environ.get("GCP_PROJECT_ID", "your-project-id")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "file-processing-topic")
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "processed_files")


def get_storage_client():
    """Initialize Cloud Storage client."""
    return storage.Client(project=PROJECT_ID)


def get_firestore_client():
    """Initialize Firestore client."""
    return firestore.Client(project=PROJECT_ID)


def get_pubsub_publisher():
    """Initialize Pub/Sub publisher client."""
    return pubsub_v1.PublisherClient()


def read_file_from_gcs(bucket_name, file_name):
    """
    Read file content from Cloud Storage.

    Args:
        bucket_name: Name of the GCS bucket
        file_name: Name/path of the file in the bucket

    Returns:
        dict with file metadata and content
    """
    client = get_storage_client()
    bucket = client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    if not blob.exists():
        raise FileNotFoundError(
            f"File {file_name} not found in bucket {bucket_name}"
        )

    # Download content
    content = blob.download_as_text()

    # Get metadata
    blob.reload()
    file_metadata = {
        "bucket": bucket_name,
        "name": file_name,
        "size": blob.size,
        "content_type": blob.content_type,
        "created": blob.time_created.isoformat() if blob.time_created else None,
        "updated": blob.updated.isoformat() if blob.updated else None,
        "md5_hash": blob.md5_hash,
        "content_length": len(content),
    }

    return {"metadata": file_metadata, "content": content}


def process_file_content(file_data):
    """
    Process the file content - customize this for your use case.

    Args:
        file_data: dict containing metadata and content from GCS

    Returns:
        dict with processing results
    """
    content = file_data["content"]
    metadata = file_data["metadata"]

    # Example processing: basic text analysis
    lines = content.strip().split("\n") if content.strip() else []
    words = content.split() if content.strip() else []

    # Try to parse as JSON if applicable
    parsed_json = None
    if metadata.get("content_type") in ("application/json", "text/json"):
        try:
            parsed_json = json.loads(content)
        except json.JSONDecodeError:
            parsed_json = None

    processing_result = {
        "file_name": metadata["name"],
        "bucket": metadata["bucket"],
        "content_type": metadata.get("content_type"),
        "file_size_bytes": metadata.get("size"),
        "line_count": len(lines),
        "word_count": len(words),
        "char_count": len(content),
        "is_valid_json": parsed_json is not None,
        "processed_at": datetime.utcnow().isoformat(),
        "status": "processed",
    }

    # If JSON, add record count if it's a list
    if parsed_json is not None and isinstance(parsed_json, list):
        processing_result["record_count"] = len(parsed_json)

    return processing_result


def write_to_firestore(document_id, data):
    """
    Write processing results to Firestore.

    NOTE: This function uses a service account with 'Datastore User' role
    which grants read/write access to ALL Firestore documents.
    For production, use a custom role with more restrictive permissions
    scoped to specific collections only.

    Args:
        document_id: Unique document identifier
        data: dict of data to store

    Returns:
        Firestore document reference
    """
    client = get_firestore_client()
    collection_ref = client.collection(FIRESTORE_COLLECTION)

    # Add write timestamp
    data["firestore_write_time"] = firestore.SERVER_TIMESTAMP

    doc_ref = collection_ref.document(document_id)
    doc_ref.set(data, merge=True)

    print(f"Written to Firestore: {FIRESTORE_COLLECTION}/{document_id}")
    return doc_ref


def publish_to_pubsub(message_data, attributes=None):
    """
    Publish processing notification to Pub/Sub.

    NOTE: This function uses a service account with 'Pub/Sub Publisher' role
    which allows publishing to ALL topics in the project.
    For production, use IAM conditions or a custom role to restrict
    publishing to specific topics only.

    Args:
        message_data: dict to publish as message body
        attributes: optional dict of message attributes

    Returns:
        Published message ID
    """
    publisher = get_pubsub_publisher()
    topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)

    # Serialize message
    message_bytes = json.dumps(message_data, default=str).encode("utf-8")

    # Publish with optional attributes
    if attributes:
        future = publisher.publish(topic_path, message_bytes, **attributes)
    else:
        future = publisher.publish(topic_path, message_bytes)

    message_id = future.result()
    print(f"Published message {message_id} to {topic_path}")
    return message_id


def create_document_id(bucket_name, file_name):
    """Create a safe Firestore document ID from bucket and file name."""
    safe_name = f"{bucket_name}__{file_name}".replace("/", "__").replace(".", "_")
    return safe_name


@functions_framework.cloud_event
def process_gcs_file(cloud_event):
    """
    Cloud Function triggered by Cloud Storage events.
    Processes the uploaded file, writes results to Firestore,
    and publishes a notification to Pub/Sub.

    Trigger: google.cloud.storage.object.v1.finalized

    SECURITY NOTE:
    This function's service account has broad permissions (Storage Admin,
    Datastore User, Pub/Sub Publisher) for MVP development speed.
    Before moving to production, follow the principle of least privilege:
    - Replace Storage Admin with Storage Object Viewer (read-only)
    - Scope Firestore access to specific collections via Security Rules
      or use a custom IAM role
    - Use IAM conditions to restrict Pub/Sub publishing to specific topics
    - Consider using separate service accounts per function

    Args:
        cloud_event: CloudEvent containing GCS event data
    """
    data = cloud_event.data

    bucket_name = data["bucket"]
    file_name = data["name"]

    print(f"Processing file: gs://{bucket_name}/{file_name}")

    # Skip processing for certain file types or paths
    skip_prefixes = ("temp/", "staging/", ".trash/")
    if any(file_name.startswith(prefix) for prefix in skip_prefixes):
        print(f"Skipping file with excluded prefix: {file_name}")
        return {"status": "skipped", "reason": "excluded_prefix"}

    try:
        # Step 1: Read file from Cloud Storage
        # NOTE: Storage Admin role is overly broad for read operations.
        # Production should use 'Storage Object Viewer' instead.
        print(f"Step 1: Reading file from GCS...")
        file_data = read_file_from_gcs(bucket_name, file_name)
        print(f"File read successfully: {file_data['metadata']['size']} bytes")

        # Step 2: Process file content
        print(f"Step 2: Processing file content...")
        processing_result = process_file_content(file_data)
        print(f"Processing complete: {processing_result['status']}")

        # Step 3: Write results to Firestore
        print(f"Step 3: Writing results to Firestore...")
        doc_id = create_document_id(bucket_name, file_name)
        write_to_firestore(doc_id, processing_result)
        print(f"Firestore write complete")

        # Step 4: Publish notification to Pub/Sub
        print(f"Step 4: Publishing to Pub/Sub...")
        pubsub_message = {
            "event_type": "file_processed",
            "bucket": bucket_name,
            "file_name": file_name,
            "processing_result": processing_result,
            "firestore_document": f"{FIRESTORE_COLLECTION}/{doc_id}",
        }
        pubsub_attributes = {
            "source": "file-processor",
            "bucket": bucket_name,
            "content_type": processing_result.get("content_type", "unknown"),
        }
        message_id = publish_to_pubsub(pubsub_message, pubsub_attributes)
        print(f"Pub/Sub publish complete: message_id={message_id}")

        result = {
            "status": "success",
            "file": f"gs://{bucket_name}/{file_name}",
            "firestore_doc": doc_id,
            "pubsub_message_id": message_id,
        }
        print(f"Processing pipeline complete: {json.dumps(result)}")
        return result

    except FileNotFoundError as e:
        error_result = {
            "status": "error",
            "error_type": "file_not_found",
            "message": str(e),
            "file": f"gs://{bucket_name}/{file_name}",
        }
        print(f"Error: {json.dumps(error_result)}")

        # Still publish error notification to Pub/Sub for monitoring
        try:
            publish_to_pubsub(
                {
                    "event_type": "processing_error",
                    "error": error_result,
                },
                {"source": "file-processor", "status": "error"},
            )
        except Exception as pub_err:
            print(f"Failed to publish error notification: {pub_err}")

        return error_result

    except Exception as e:
        error_result = {
            "status": "error",
            "error_type": type(e).__name__,
            "message": str(e),
            "file": f"gs://{bucket_name}/{file_name}",
        }
        print(f"Unexpected error: {json.dumps(error_result)}")

        # Attempt to publish error notification
        try:
            publish_to_pubsub(
                {
                    "event_type": "processing_error",
                    "error": error_result,
                },
                {"source": "file-processor", "status": "error"},
            )
        except Exception as pub_err:
            print(f"Failed to publish error notification: {pub_err}")

        raise


@functions_framework.http
def process_file_http(request):
    """
    HTTP-triggered version for testing and manual processing.

    Expected JSON body:
    {
        "bucket": "my-bucket",
        "name": "path/to/file.txt"
    }

    SECURITY NOTE: Same broad permissions apply as the event-triggered version.
    Additionally, this HTTP endpoint should have authentication enabled
    in production (e.g., require IAM authentication, not allow-unauthenticated).
    """
    # Validate request
    if request.method != "POST":
        return json.dumps({"error": "Method not allowed. Use POST."}), 405

    request_json = request.get_json(silent=True)
    if not request_json:
        return json.dumps({"error": "Request body must be JSON"}), 400

    bucket_name = request_json.get("bucket")
    file_name = request_json.get("name")

    if not bucket_name or not file_name:
        return (
            json.dumps({"error": "Both 'bucket' and 'name' fields are required"}),
            400,
        )

    try:
        # Read and process
        file_data = read_file_from_gcs(bucket_name, file_name)
        processing_result = process_file_content(file_data)

        # Write to Firestore
        doc_id = create_document_id(bucket_name, file_name)
        write_to_firestore(doc_id, processing_result)

        # Publish to Pub/Sub
        pubsub_message = {
            "event_type": "file_processed_manual",
            "bucket": bucket_name,
            "file_name": file_name,
            "processing_result": processing_result,
            "firestore_document": f"{FIRESTORE_COLLECTION}/{doc_id}",
        }
        message_id = publish_to_pubsub(
            pubsub_message,
            {"source": "file-processor-http", "bucket": bucket_name},
        )

        result = {
            "status": "success",
            "file": f"gs://{bucket_name}/{file_name}",
            "processing_result": processing_result,
            "firestore_doc": f"{FIRESTORE_COLLECTION}/{doc_id}",
            "pubsub_message_id": message_id,
        }
        return json.dumps(result, default=str), 200

    except FileNotFoundError as e:
        return json.dumps({"error": "File not found", "detail": str(e)}), 404
    except Exception as e:
        return (
            json.dumps(
                {"error": "Processing failed", "detail": str(e), "type": type(e).__name__}
            ),
            500,
        )


